using Microsoft.EntityFrameworkCore;
class BlogContext : DbContext
{
    public DbSet<Blog> Blogs => Set<Blog>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Blog>(entity =>
        {
            // Breaking change 1: EF 9 removed Discriminator property from Cosmos documents.
            // Existing docs have "Discriminator":"Blog" — tell EF 9 to keep using it.
            entity.HasDiscriminator<string>("Discriminator").HasValue("Blog");

            // Breaking change 2: EF 9 changed id format from "Blog|<key>" to just "<key>".
            // Existing docs use "Blog|1" format — preserve it with an id factory.
            entity.HasPartitionKey(b => b.Id);
            entity.Property(b => b.Id)
                .ToJsonProperty("id")
                .HasValueGenerator<BlogIdValueGenerator>();

            // Breaking change 3: Cosmos DB does not support indexes defined via EF Core.
            // HasIndex() now throws at model validation in EF 9.
            // Removed: entity.HasIndex(b => b.Name);
            // Manage indexes via the Azure portal or Cosmos DB indexing policy instead.
        });
    }

    protected override void OnConfiguring(DbContextOptionsBuilder options)
    {
        // Breaking change 4: EF 9 uses sync-over-async I/O by default for Cosmos,
        // which now throws unless explicitly opted in. Existing sync code (ToList,
        // SaveChanges) in SyncJob requires this flag.
        options.UseCosmos("<connection-string>", "<database>",
            cosmosOptions => cosmosOptions.AllowSynchronousIO());
    }
}

