arguments.new_str:
class SyncJob
{
    // Breaking change 4 fix: prefer async APIs with Cosmos provider in EF 9.
    // Alternatively, AllowSynchronousIO() is configured in BlogContext.OnConfiguring.
    async Task RunAsync(BlogContext context)
    {
        var blogs = await context.Blogs.ToListAsync();
        foreach (var b in blogs) { b.Name = b.Name.Trim(); }
        await context.SaveChangesAsync();
    }

    // Breaking change 5: Raw SQL queries referencing "Discriminator" still work,
    // but only if HasDiscriminator is configured (see BlogContext).
    // Queries like: SELECT * FROM c WHERE c.Discriminator = 'Blog'
    // will continue to match existing documents because the property is preserved.
}

